#!/usr/bin/perl
use strict;
use warnings;
use DBI;
use Carp qw(croak);

# Load environment variables from a secure configuration
# Set these environment variables before running:
#   export LEGACY_DB_NAME=legacy_db
#   export LEGACY_DB_HOST=localhost
#   export LEGACY_DB_PORT=3306
#   export LEGACY_DB_USER=dbuser
#   export LEGACY_DB_PASS=<your_secure_password>

sub load_config_from_file {
    my ($config_file) = @_;
    my %config;

    # Config file should be chmod 600, owned by the application user
    my $file_path = $config_file || "$ENV{HOME}/.legacy_db.conf";

    if (-e $file_path) {
        # Verify file permissions are restrictive (owner read/write only)
        my $mode = (stat($file_path))[2] & 07777;
        if ($mode & 0077) {
            croak "Configuration file $file_path has insecure permissions "
                . sprintf("(%04o)", $mode)
                . ". Please run: chmod 600 $file_path";
        }

        open my $fh, '<', $file_path
            or croak "Cannot open config file $file_path: $!";
        while (my $line = <$fh>) {
            chomp $line;
            next if $line =~ /^\s*#/;    # skip comments
            next if $line =~ /^\s*$/;    # skip blank lines
            if ($line =~ /^\s*(\w+)\s*=\s*(.+?)\s*$/) {
                $config{$1} = $2;
            }
        }
        close $fh;
    }

    return %config;
}

sub get_db_config {
    # Priority: environment variables > config file > defaults (no secrets in defaults)
    my %file_config = load_config_from_file();

    my %config = (
        db_name => $ENV{LEGACY_DB_NAME} // $file_config{db_name} // 'legacy_db',
        db_host => $ENV{LEGACY_DB_HOST} // $file_config{db_host} // 'localhost',
        db_port => $ENV{LEGACY_DB_PORT} // $file_config{db_port} // '3306',
        db_user => $ENV{LEGACY_DB_USER} // $file_config{db_user},
        db_pass => $ENV{LEGACY_DB_PASS} // $file_config{db_pass},
    );

    # Validate that credentials are provided and not placeholder values
    unless (defined $config{db_user} && length $config{db_user}) {
        croak "Database username not configured. "
            . "Set LEGACY_DB_USER environment variable or add db_user to config file.";
    }

    unless (defined $config{db_pass} && length $config{db_pass}) {
        croak "Database password not configured. "
            . "Set LEGACY_DB_PASS environment variable or add db_pass to config file.";
    }

    return %config;
}

sub connect_to_database {
    my %config = get_db_config();

    my $dsn = sprintf(
        "DBI:mysql:database=%s;host=%s;port=%s",
        $config{db_name},
        $config{db_host},
        $config{db_port},
    );

    my $dbh = DBI->connect(
        $dsn,
        $config{db_user},
        $config{db_pass},
        {
            RaiseError       => 1,
            AutoCommit       => 1,
            PrintError       => 0,
            mysql_enable_utf8 => 1,
            mysql_auto_reconnect => 1,
            # Use secure connection if available
            mysql_ssl        => 1,
        },
    ) or croak "Failed to connect to database: " . DBI->errstr;

    # Verify connection is alive
    $dbh->ping()
        or croak "Database connection established but ping failed.";

    return $dbh;
}

sub disconnect_from_database {
    my ($dbh) = @_;
    if ($dbh && $dbh->ping()) {
        $dbh->disconnect();
    }
    return;
}

# --- Main execution ---

my $dbh;

eval {
    $dbh = connect_to_database();
    print "Successfully connected to the legacy database.\n";

    # Example: verify connectivity with a simple query
    my $sth = $dbh->prepare("SELECT 1 AS connection_test");
    $sth->execute();
    my $row = $sth->fetchrow_hashref();
    if ($row && $row->{connection_test} == 1) {
        print "Database connection verified successfully.\n";
    }
    $sth->finish();

    # --- Add your application logic here ---

};
if (my $err = $@) {
    warn "Database error: $err\n";
    disconnect_from_database($dbh) if $dbh;
    exit 1;
}

disconnect_from_database($dbh);
exit 0;

